#include <bits/stdc++.h>
using namespace std;

const int N=100;

int n,m,t,act;
long long p[N][N],a[N][N][N],tmp[N][N],mx;
long long ans[N][N],base[N][N];
char g[N][N],c[N][N];

int cal(int x,int y){
    return (x-1)*m+y;
}

int main(){
    scanf("%d%d%d%d",&n,&m,&t,&act);
    for(int i=1;i<=n;i++)
        scanf("%s",g[i]+1);
    for(int i=0;i<act;i++)
        scanf("%s",c[i]);
    for(int i=1;i<=60;i++){
        a[i][0][0]=1;
        for(int j=1;j<=n;j++)
            for(int k=1;k<=m;k++){
            	int len=strlen(c[g[j][k]-'0']);
                char op=c[g[j][k]-'0'][(i%len+len-1)%len];
                if(op=='N'&& j>1)
                    a[i][cal(j,k)][cal(j-1,k)]=1;
                if(op=='W' && k>1)
                    a[i][cal(j,k)][cal(j,k-1)]=1;
                if(op=='S' && j<n)
                    a[i][cal(j,k)][cal(j+1,k)]=1;
                if(op=='E' && k<m)
                    a[i][cal(j,k)][cal(j,k+1)]=1;
                if('0'<=op && op<='9')
                    a[i][0][cal(j,k)]=op-'0',a[i][cal(j,k)][cal(j,k)]=1;
            }
    }
    //puts("OK1");
    for(int i=0;i<=n*m;i++)
        p[i][i]=1;
    for(int ti=1;ti<=60;ti++){
        for(int i=0;i<=n*m;i++)
            for(int j=0;j<=n*m;j++)
                tmp[i][j]=p[i][j],p[i][j]=0;
        for(int i=0;i<=n*m;i++)
            for(int j=0;j<=n*m;j++)
                for(int k=0;k<=n*m;k++)
                    p[i][j]+=tmp[i][k]*a[ti][k][j];
    }
    //puts("OK2");
	int q=t/60;
    for(int i=0;i<=n*m;i++)
        for(int j=0;j<=n*m;j++)
            base[i][j]=p[i][j],ans[i][j]=(i==j);
    while(q){
        if(q&1){
            for(int i=0;i<=n*m;i++)
                for(int j=0;j<=n*m;j++)
                    tmp[i][j]=ans[i][j],ans[i][j]=0;
            for(int i=0;i<=n*m;i++)
                for(int j=0;j<=n*m;j++)
                    for(int k=0;k<=n*m;k++)
                        ans[i][j]+=tmp[i][k]*base[k][j];
        }
        for(int i=0;i<=n*m;i++)
            for(int j=0;j<=n*m;j++)
                tmp[i][j]=base[i][j],base[i][j]=0;
        for(int i=0;i<=n*m;i++)
            for(int j=0;j<=n*m;j++)
                for(int k=0;k<=n*m;k++)
                    base[i][j]+=tmp[i][k]*tmp[k][j];
        q>>=1;
    }
    //puts("OK3");
    for(int ti=1;ti<=t%60;ti++){
        for(int i=0;i<=n*m;i++)
            for(int j=0;j<=n*m;j++)
                tmp[i][j]=ans[i][j],ans[i][j]=0;
        for(int i=0;i<=n*m;i++)
            for(int j=0;j<=n*m;j++)
                for(int k=0;k<=n*m;k++)
                    ans[i][j]+=tmp[i][k]*a[ti][k][j];
    }
    //puts("OK4");
    for(int i=1;i<=n*m;i++){
        /*
		printf("%lld ",ans[0][i]);
        if(i%m==0)
            puts("");
        */
        mx=max(mx,ans[0][i]);
    }
    printf("%lld",mx);
    return 0;
}
